use std::sync::{Arc, Mutex};

fn main() {
    // This is the culprit: holding `lock` forever during the long-running build loop
    let mut lock = mutex.lock().unwrap();

    let mut state = Arc::new(Mutex::new("building".to_string()));

    println!("Starting compilation... this will take a while."); // This is where it hangs indefinitely

    loop {
        lock.lock()
            .unwrap();

        match state.get_mut() {
            Ok(msg) => {
                msg.clone()
                    .await;
            }
            Err(_) => break, // We just exit the loop here without doing anything
        }
    }
}
```

The problem is clear: we're trying to update a thread-local variable while holding an exclusive lock. That's not going to work in a multi-threaded build environment.

